import { objectHash } from '@jbrowse/core/util'
import { generateUnsupportedTrackConf } from '@jbrowse/core/util/tracks'

function getSubtracks(track, trackPath = []) {
  if (track.members) {
    return Object.values(track.members).flatMap((subTrack) =>
      getSubtracks(
        subTrack,
        track.shortLabel ? trackPath.concat([track.shortLabel]) : trackPath,
      ),
    )
  }
  track.categories = trackPath
  return [track]
}

export function generateTracks(trackDb, assemblyName, sequenceAdapter) {
  const { configuration } = trackDb
  const subTracks = getSubtracks({ members: configuration })
  return subTracks.map((subTrack) => {
    const ret = makeTrackConfig(subTrack, trackDb.hub.url, sequenceAdapter)
    return {
      ...makeTrackConfig(subTrack, trackDb.hub.url, sequenceAdapter),
      trackId: `trackhub-registry-${objectHash(ret)}`,
      assemblyNames: [assemblyName],
    }
  })
}

function makeTrackConfig(track, trackDbUrl, sequenceAdapter) {
  const trackType = track.type
  let baseTrackType = trackType.split(' ')[0].toLowerCase()
  if (
    baseTrackType === 'bam' &&
    track.bigDataUrl.toLowerCase().endsWith('cram')
  ) {
    baseTrackType = 'cram'
  }
  const { bigDataUrl } = track
  const bigDataLocation = {
    uri: new URL(bigDataUrl, trackDbUrl).href,
    locationType: 'UriLocation',
  }
  const { categories } = track
  let bigDataIndexLocation
  switch (baseTrackType) {
    case 'bam':
      if (trackDbUrl) {
        bigDataIndexLocation = track.bigDataIndex
          ? {
              uri: new URL(track.bigDataIndex, trackDbUrl).href,
              locationType: 'UriLocation',
            }
          : {
              uri: new URL(`${track.bigDataUrl}.bai`, trackDbUrl).href,
              locationType: 'UriLocation',
            }
      } else {
        bigDataIndexLocation = track.bigDataIndex
          ? { localPath: track.bigDataIndex, locationType: 'LocalPathLocation' }
          : {
              localPath: `${track.bigDataUrl}.bai`,
              locationType: 'LocalPathLocation',
            }
      }
      return {
        type: 'AlignmentsTrack',
        name: track.shortLabel,
        description: track.longLabel,
        category: categories,
        adapter: {
          type: 'BamAdapter',
          bamLocation: bigDataLocation,
          index: {
            location: bigDataIndexLocation,
          },
        },
      }
    case 'bed':
      return generateUnsupportedTrackConf(
        track.shortLabel,
        baseTrackType,
        categories,
      )
    case 'bed5floatscore':
      return generateUnsupportedTrackConf(
        track.shortLabel,
        baseTrackType,
        categories,
      )
    case 'bedgraph':
      return generateUnsupportedTrackConf(
        track.shortLabel,
        baseTrackType,
        categories,
      )
    case 'bedrnaelements':
      return generateUnsupportedTrackConf(
        track.shortLabel,
        baseTrackType,
        categories,
      )
    case 'bigbarchart':
      return generateUnsupportedTrackConf(
        track.shortLabel,
        baseTrackType,
        categories,
      )
    case 'bigbed':
      return {
        type: 'FeatureTrack',
        name: track.shortLabel,
        description: track.longLabel,
        category: categories,
        adapter: {
          type: 'BigBedAdapter',
          bigBedLocation: bigDataLocation,
        },
      }
    case 'bigchain':
      return generateUnsupportedTrackConf(
        track.shortLabel,
        baseTrackType,
        categories,
      )
    case 'biginteract':
      return generateUnsupportedTrackConf(
        track.shortLabel,
        baseTrackType,
        categories,
      )
    case 'bigmaf':
      return generateUnsupportedTrackConf(
        track.shortLabel,
        baseTrackType,
        categories,
      )
    case 'bigpsl':
      return generateUnsupportedTrackConf(
        track.shortLabel,
        baseTrackType,
        categories,
      )
    case 'bigwig':
      return {
        type: 'QuantitativeTrack',
        name: track.shortLabel,
        description: track.longLabel,
        category: categories,
        adapter: {
          type: 'BigWigAdapter',
          bigWigLocation: bigDataLocation,
        },
      }
    case 'broadpeak':
      return generateUnsupportedTrackConf(
        track.shortLabel,
        baseTrackType,
        categories,
      )
    case 'coloredexon':
      return generateUnsupportedTrackConf(
        track.shortLabel,
        baseTrackType,
        categories,
      )
    case 'cram':
      if (trackDbUrl) {
        bigDataIndexLocation = track.bigDataIndex
          ? {
              uri: new URL(track.bigDataIndex, trackDbUrl).href,
              locationType: 'UriLocation',
            }
          : {
              uri: new URL(`${track.bigDataUrl}.bai`, trackDbUrl).href,
              locationType: 'UriLocation',
            }
      } else {
        bigDataIndexLocation = track.bigDataIndex
          ? { localPath: track.bigDataIndex, locationType: 'LocalPathLocation' }
          : {
              localPath: `${track.bigDataUrl}.bai`,
              locationType: 'LocalPathLocation',
            }
      }
      return {
        type: 'AlignmentsTrack',
        name: track.shortLabel,
        description: track.longLabel,
        category: categories,
        adapter: {
          type: 'CramAdapter',
          bamLocation: bigDataLocation,
          index: { location: bigDataIndexLocation },
          sequenceAdapter,
        },
      }
    case 'gvf':
      return generateUnsupportedTrackConf(
        track.shortLabel,
        baseTrackType,
        categories,
      )
    case 'ld2':
      return generateUnsupportedTrackConf(
        track.shortLabel,
        baseTrackType,
        categories,
      )
    case 'narrowpeak':
      return generateUnsupportedTrackConf(
        track.shortLabel,
        baseTrackType,
        categories,
      )
    case 'peptidemapping':
      return generateUnsupportedTrackConf(
        track.shortLabel,
        baseTrackType,
        categories,
      )
    case 'vcftabix':
      return generateUnsupportedTrackConf(
        track.shortLabel,
        baseTrackType,
        categories,
      )
    case 'wig':
      return generateUnsupportedTrackConf(
        track.shortLabel,
        baseTrackType,
        categories,
      )
    case 'wigmaf':
      return generateUnsupportedTrackConf(
        track.shortLabel,
        baseTrackType,
        categories,
      )
    default:
      throw new Error(`Unsupported track type: ${baseTrackType}`)
  }
}
